#include <bits/stdc++.h>
using namespace std;
struct DSU { vector<int> par, rk; DSU(int n): par(n+1), rk(n+1, 0){ iota(par.begin(), par.end(), 0);} int find(int x){ return par[x]==x ? x : par[x]=find(par[x]); } bool uni(int a, int b){ a=find(a); b=find(b); if(a==b) return false; if(rk[a]<rk[b]) swap(a,b); par[b]=a; if(rk[a]==rk[b]) rk[a]++; return true; }};
int main(){
    ios_base::sync_with_stdio(false); cin.tie(NULL);
    int n, m; cin >> n >> m;
    vector<tuple<long long,int,int>> e(m);
    for (auto &[w,u,v] : e) cin >> u >> v >> w;
    sort(e.begin(), e.end());
    DSU d(n); long long total = 0;
    for (auto &[w,u,v] : e) if (d.uni(u, v)) total += w;
    cout << total << '\n';
}
